const numbersToWords=w=>{const E=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(w<0x14)return E[w];if(w<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](w/0xa)]+(w%0xa?'\x20'+E[w%0xa]:'');if(w<0x3e8){const Z=Math['floor'](w/0x64),J=w%0x64;return(0x1===Z?'εκατό':0x2===Z?'διακόσια':0x3===Z?'τριακόσια':0x4===Z?'τετρακόσια':0x5===Z?'πεντακόσια':0x6===Z?'εξακόσια':0x7===Z?'επτακόσια':0x8===Z?'οκτακόσια':0x9===Z?'εννιακόσια':'')+(J?'\x20'+numbersToWords(J):'');}return w<0xf4240?numbersToWords(Math['floor'](w/0x3e8))+'\x20χιλιάδες'+(w%0x3e8?'\x20'+numbersToWords(w%0x3e8):''):numbersToWords(Math['floor'](w/0xf4240))+'\x20εκατομμύρια'+(w%0xf4240?'\x20'+numbersToWords(w%0xf4240):'');},numberToText=(w,E='money')=>{const Z=Math['floor'](w),J=Math['round'](0x64*(w-Z));let g=numbersToWords(Z),u=J>0x0?numbersToWords(J):'';switch(E){case'money':return u?g+'\x20ευρώ\x20και\x20'+u+'\x20λεπτά':g+'\x20ευρώ';case'time':return u?g+'\x20ώρες\x20και\x20'+u+'\x20λεπτά':g+'\x20ώρες';default:return u?g+'\x20και\x20'+u:''+g;}};